export function validateHrxCp929AdminPolicyDeniedStateBridgeCoverage(planPack) {
  const binding = HRX_CP929_PACK_BINDING;
  const requirements = HRX_CP929_REQUIREMENTS;
  const errors = [];
  if (!planPack) errors.push(`${binding.pack_id} plan pack is required`);
  if (planPack?.pack_id !== binding.pack_id) errors.push(`plan pack must be ${binding.pack_id}`);
  if (planPack?.risk_class !== binding.risk_class) errors.push(`${binding.pack_id} risk class drift`);
  if (planPack?.unit_count !== binding.unit_count) errors.push(`${binding.pack_id} unit count drift`);
  const units = planPack?.included_units ?? [];
  const unitIds = units.map((unit) => unit.id);
  if (unitIds[0] !== binding.first_unit_id) errors.push(`${binding.pack_id} first unit drift`);
  if (unitIds.at(-1) !== binding.last_unit_id) errors.push(`${binding.pack_id} last unit drift`);
  if (new Set(unitIds).size !== unitIds.length) errors.push(`${binding.pack_id} duplicate unit IDs`);
  if (units.some((unit) => unit.program_id !== "RP30")) errors.push(`${binding.pack_id} must only include RP30 units`);
  if (units.some((unit) => unit.hrx_embedded !== true)) errors.push(`${binding.pack_id} must only include HRX embedded units`);
  const summary = createHrxCp929AdminPolicyDeniedStateBridgeCoverageSummary(planPack);
  for (const [name, count] of Object.entries(requirements.deliverable_counts)) {
    if (summary.by_deliverable[name] !== count) errors.push(`${binding.pack_id} ${name} deliverable distribution drift`);
  }
  for (const [name, count] of Object.entries(requirements.phase_counts)) {
    if (summary.by_phase[name] !== count) errors.push(`${binding.pack_id} ${name} phase distribution drift`);
  }
  for (const [name, count] of Object.entries(requirements.micro_phase_row_counts)) {
    if (summary.by_micro_phase[name] !== count) errors.push(`${binding.pack_id} ${name} micro distribution drift`);
  }
  for (const [name, count] of Object.entries(requirements.micro_title_row_counts)) {
    if (summary.by_micro_title[name] !== count) errors.push(`${binding.pack_id} ${name} title distribution drift`);
  }
  for (const [microId, titles] of Object.entries(requirements.required_section_rows)) {
    const sectionUnits = units.filter((unit) => unit.source_micro_phase_id === microId);
    if (sectionUnits.length !== titles.length) errors.push(`${binding.pack_id} ${microId} row count drift`);
    const sectionTitles = sectionUnits.map((unit) => unit.title);
    for (const title of titles) {
      if (!sectionTitles.includes(title)) errors.push(`${binding.pack_id} ${microId} missing row ${title}`);
    }
  }
  return freezeValidation(binding, { valid: errors.length === 0, errors: Object.freeze(errors), summary });
}

export function validateHrxCp929AdminPolicyDeniedStateBridgeDescriptor(
  descriptor = createHrxCp929AdminPolicyDeniedStateBridgeDescriptor(),
  contractProjection = {},
) {
  const binding = HRX_CP929_PACK_BINDING;
  const requirements = HRX_CP929_REQUIREMENTS;
  const caseSet = descriptor.hrx_admin_policy_denied_state_bridge_case_set ?? createHrxCp929AdminPolicyDeniedStateBridgeCaseSet();
  const errors = [];
  if (descriptor.descriptor !== "HrxCp929AdminPolicyDeniedStateBridgeDescriptor") errors.push(`${binding.pack_id} descriptor type drift`);
  if (descriptor.source_descriptor !== "HrxCp928AiReviewAdminPolicyBridgeDescriptor") errors.push(`${binding.pack_id} source descriptor drift`);
  if (descriptor.program_contract?.program_id !== HRX_PROGRAM_CONTRACT.program_id) errors.push(`${binding.pack_id} program id drift`);
  if (descriptor.program_contract?.hrx_embedded !== true || descriptor.program_contract?.separate_product !== false) errors.push(`${binding.pack_id} HRX product boundary drift`);
  if (descriptor.authority_boundary?.claude_is_final_approval !== false) errors.push(`${binding.pack_id} Claude must not be final approval`);
  if (descriptor.authority_boundary?.local_validation_claims_enterprise_trust !== false) errors.push(`${binding.pack_id} local validation must not claim enterprise trust`);
  if (descriptor.authority_boundary?.human_final_approval_required_for_runtime_opening !== true) errors.push(`${binding.pack_id} human approval boundary drift`);
  if (descriptor.authority_boundary?.runtime_opening_pack_id !== binding.next_pack_id) errors.push(`${binding.pack_id} runtime opening pack drift`);
  if (caseSet.section_count !== Object.keys(requirements.required_section_rows).length) errors.push(`${binding.pack_id} section count drift`);
  if (caseSet.row_count !== binding.unit_count) errors.push(`${binding.pack_id} case row count drift`);
  const rowChecks = {
    "RP30.P04.M04": {
      descriptor: "admin_policy_descriptor",
      entity: "AdminPolicy",
      fields: ["admin_policy_runtime_opened", "admin_policy_record_write_opened", "admin_policy_rule_execution_opened", "admin_policy_finalization_allowed"],
    },
    "RP30.P04.M05": {
      descriptor: "denied_state_descriptor",
      entity: "DeniedState",
      fields: ["denied_state_runtime_opened", "denied_state_record_write_opened", "denied_state_access_granted", "denied_state_policy_bypass_allowed"],
    },
  };
  for (const [microId, titles] of Object.entries(requirements.required_section_rows)) {
    const section = caseSet.sections?.[microId];
    if (!section) {
      errors.push(`${binding.pack_id} missing section ${microId}`);
      continue;
    }
    if (section.row_count !== titles.length) errors.push(`${binding.pack_id} ${microId} row count drift`);
    for (const title of titles) {
      const key = hrxRowKey(title);
      const row = section.rows?.[key];
      if (!row) {
        errors.push(`${binding.pack_id} ${microId} missing row ${key}`);
        continue;
      }
      if (row.descriptor_only !== true || row.hrx_embedded !== true || row.domain_bridge_descriptor !== true) errors.push(`${binding.pack_id} ${key} must be embedded descriptor-only bridge`);
      if (row.separate_product_created !== false) errors.push(`${binding.pack_id} ${key} must not create separate HRX product`);
      if (row.runtime_execution !== false || row.payroll_calculation_runtime_executed !== false || row.hr_ai_final_judgment_executed !== false) {
        errors.push(`${binding.pack_id} ${key} runtime boundary drift`);
      }
      if (row.permission_decision_written !== false || row.audit_event_written !== false || row.product_state_written !== false) {
        errors.push(`${binding.pack_id} ${key} no-write boundary drift`);
      }
      if (
        row.real_employee_data_included !== false
        || row.real_candidate_data_included !== false
        || row.real_payroll_data_included !== false
        || row.credential_or_secret_included !== false
      ) {
        errors.push(`${binding.pack_id} ${key} real-data or secret boundary drift`);
      }
      const check = rowChecks[microId];
      if (!check) {
        errors.push(`${binding.pack_id} ${microId} missing row check`);
        continue;
      }
      if (row[check.descriptor] !== true || row.entity_name !== check.entity) errors.push(`${binding.pack_id} ${key} ${check.entity} descriptor drift`);
      if (check.entity === "DeniedState" && row.denied_state_security_audit_descriptor !== true) errors.push(`${binding.pack_id} ${key} DeniedState security-audit descriptor drift`);
      for (const field of check.fields) {
        if (row[field] !== false) errors.push(`${binding.pack_id} ${key} ${field} must remain false`);
      }
      if (row.sensitive_hr_guard_required !== true || row.h30_review_only !== true || row.c30_read_only !== true) {
        errors.push(`${binding.pack_id} ${key} review guard drift`);
      }
    }
  }
  const baseline = descriptor.baseline_decisions ?? {};
  if (baseline.hrx_embedded_inside_law_firm_os !== true) errors.push(`${binding.pack_id} embedded boundary drift`);
  if (baseline.separate_hrx_product_created !== false) errors.push(`${binding.pack_id} separate product drift`);
  if (baseline.admin_policy_descriptor_only !== true) errors.push(`${binding.pack_id} AdminPolicy descriptor-only drift`);
  if (baseline.admin_policy_runtime_deferred !== true) errors.push(`${binding.pack_id} AdminPolicy runtime deferral drift`);
  if (baseline.admin_policy_record_writes_deferred !== true) errors.push(`${binding.pack_id} AdminPolicy record write deferral drift`);
  if (baseline.admin_policy_rule_execution_deferred !== true) errors.push(`${binding.pack_id} AdminPolicy rule execution drift`);
  if (baseline.admin_policy_finalization_deferred !== true) errors.push(`${binding.pack_id} AdminPolicy finalization drift`);
  if (baseline.denied_state_descriptor_only !== true) errors.push(`${binding.pack_id} DeniedState descriptor-only drift`);
  if (baseline.denied_state_security_audit_descriptor !== true) errors.push(`${binding.pack_id} DeniedState security-audit drift`);
  if (baseline.denied_state_runtime_deferred !== true) errors.push(`${binding.pack_id} DeniedState runtime deferral drift`);
  if (baseline.denied_state_record_writes_deferred !== true) errors.push(`${binding.pack_id} DeniedState record write deferral drift`);
  if (baseline.denied_state_access_grants_closed !== true) errors.push(`${binding.pack_id} DeniedState access grant drift`);
  if (baseline.denied_state_policy_bypass_closed !== true) errors.push(`${binding.pack_id} DeniedState policy bypass drift`);
  if (baseline.payroll_calculation_runtime_deferred !== true) errors.push(`${binding.pack_id} payroll runtime deferral drift`);
  if (baseline.hr_ai_final_judgment_allowed !== false) errors.push(`${binding.pack_id} HR AI final judgment drift`);
  if (baseline.real_employee_candidate_payroll_document_data_allowed !== false) errors.push(`${binding.pack_id} real HR data allowance drift`);
  const entityChecks = {
    AdminPolicy: ["admin_policy_runtime_opened", "admin_policy_record_write_opened", "admin_policy_rule_execution_opened", "admin_policy_finalization_allowed"],
    DeniedState: ["denied_state_runtime_opened", "denied_state_record_write_opened", "denied_state_access_granted", "denied_state_policy_bypass_allowed"],
  };
  for (const [entity, fields] of Object.entries(entityChecks)) {
    for (const field of fields) {
      if (descriptor.domain_entities?.[entity]?.[field] !== false) errors.push(`${binding.pack_id} ${entity} domain boundary drift`);
    }
  }
  if (descriptor.domain_entities?.DeniedState?.denied_state_security_audit_descriptor !== true) errors.push(`${binding.pack_id} DeniedState domain descriptor drift`);
  if (descriptor.hermes_packet?.gate !== binding.hermes_gate || descriptor.hermes_packet?.emits_runtime_receipt !== false) errors.push(`${binding.pack_id} Hermes packet drift`);
  if (descriptor.claude_packet?.gate !== binding.claude_gate || descriptor.claude_packet?.read_only !== true) errors.push(`${binding.pack_id} Claude packet drift`);
  if (descriptor.claude_packet?.promotes_claude_to_final_approval !== false) errors.push(`${binding.pack_id} Claude packet approval drift`);
  if (descriptor.closeout_handoff?.to_pack_id !== binding.next_pack_id || descriptor.closeout_handoff?.next_subphase_id !== binding.next_subphase_id) errors.push(`${binding.pack_id} handoff drift`);
  for (const capability of requirements.required_capabilities) {
    if (!descriptor.required_capabilities?.includes(capability)) errors.push(`${binding.pack_id} descriptor missing capability ${capability}`);
  }
  for (const gate of requirements.safety_gates) {
    if (!descriptor.safety_gates?.includes(gate)) errors.push(`${binding.pack_id} descriptor missing safety gate ${gate}`);
  }
  for (const guard of requirements.required_no_leak_guards) {
    if (!descriptor.no_leak_guards?.includes(guard)) errors.push(`${binding.pack_id} descriptor missing no-leak guard ${guard}`);
  }
  if (contractProjection.latest_pack?.pack_id && contractProjection.latest_pack.pack_id !== binding.pack_id) errors.push(`${binding.pack_id} contract projection pack drift`);
  return freezeValidation(binding, { valid: errors.length === 0, errors: Object.freeze(errors), descriptor, contractProjection });
}

