  if (baseline.ai_review_queue_descriptor_only !== true) errors.push(`${binding.pack_id} AIReviewQueue descriptor-only drift`);
  if (baseline.ai_review_queue_runtime_deferred !== true) errors.push(`${binding.pack_id} AIReviewQueue runtime deferral drift`);
  if (baseline.ai_review_queue_record_writes_deferred !== true) errors.push(`${binding.pack_id} AIReviewQueue record write deferral drift`);
  if (baseline.ai_review_queue_review_actions_deferred !== true) errors.push(`${binding.pack_id} AIReviewQueue review action drift`);
  if (baseline.ai_review_queue_final_judgment_deferred !== true) errors.push(`${binding.pack_id} AIReviewQueue final judgment drift`);
  if (baseline.payroll_calculation_runtime_deferred !== true) errors.push(`${binding.pack_id} payroll runtime deferral drift`);
  if (baseline.hr_ai_final_judgment_allowed !== false) errors.push(`${binding.pack_id} HR AI final judgment drift`);
