  if (baseline.synthetic_tenant_descriptor_only !== true) errors.push(`${binding.pack_id} SyntheticTenant descriptor-only drift`);
  if (baseline.synthetic_tenant_runtime_deferred !== true) errors.push(`${binding.pack_id} SyntheticTenant runtime deferral drift`);
