  if (baseline.candidate_fixture_descriptor_only !== true) errors.push(`${binding.pack_id} CandidateFixture descriptor-only drift`);
  if (baseline.candidate_fixture_runtime_deferred !== true) errors.push(`${binding.pack_id} CandidateFixture runtime deferral drift`);
  if (baseline.candidate_fixture_record_writes_deferred !== true) errors.push(`${binding.pack_id} CandidateFixture record write deferral drift`);
