  if (baseline.employee_fixture_foundation_descriptor_only !== true) errors.push(`${binding.pack_id} EmployeeFixture descriptor-only drift`);
  if (baseline.employee_fixture_runtime_deferred !== true) errors.push(`${binding.pack_id} EmployeeFixture runtime deferral drift`);
  if (baseline.employee_fixture_record_writes_deferred !== true) errors.push(`${binding.pack_id} EmployeeFixture record write deferral drift`);
