  if (baseline.candidate_fixture_permission_bypass_deferred !== true) errors.push(`${binding.pack_id} CandidateFixture permission bypass drift`);
  if (baseline.candidate_fixture_identity_link_runtime_deferred !== true) errors.push(`${binding.pack_id} CandidateFixture identity-link runtime drift`);
  if (baseline.leave_fixture_foundation_descriptor_only !== true) errors.push(`${binding.pack_id} LeaveFixture descriptor-only drift`);
  if (baseline.leave_fixture_runtime_deferred !== true) errors.push(`${binding.pack_id} LeaveFixture runtime deferral drift`);
  if (baseline.leave_fixture_record_writes_deferred !== true) errors.push(`${binding.pack_id} LeaveFixture record write deferral drift`);
